    private void EnsureConfig()
    {
        if (config != null)
        {
            return;
        }

        if (ProgressionService.Instance != null)
        {
            config = ProgressionService.Instance.Config;
        }
    }

    private void EnsureTrackLayout()
    {
        if (trackScrollRect != null
            && trackContent != null)
        {
            return;
        }

        if (trackScrollRect == null)
        {
            trackScrollRect =
                GetComponentInChildren<ScrollRect>(true);
        }

        if (trackScrollRect == null)
        {
            var scrollGo = new GameObject(
                "TrackScroll",
                typeof(RectTransform),
                typeof(ScrollRect),
                typeof(Image),
                typeof(Mask));

            scrollGo.transform.SetParent(
                transform, false);

            var scrollRect =
                scrollGo.GetComponent<RectTransform>();
            scrollRect.anchorMin =
                new Vector2(0f, 0.05f);
            scrollRect.anchorMax =
                new Vector2(1f, 0.7f);
            scrollRect.offsetMin =
                new Vector2(40f, 0f);
            scrollRect.offsetMax =
                new Vector2(-40f, 0f);

            var scrollBg =
                scrollGo.GetComponent<Image>();
            scrollBg.color =
                new Color(0.1f, 0.1f, 0.1f, 0.6f);

            var mask = scrollGo.GetComponent<Mask>();
            mask.showMaskGraphic = true;

            trackScrollRect =
                scrollGo.GetComponent<ScrollRect>();
            trackScrollRect.horizontal = true;
            trackScrollRect.vertical = false;
            trackScrollRect.movementType =
                ScrollRect.MovementType.Elastic;

            var viewportGo = new GameObject(
                "Viewport",
                typeof(RectTransform));

            viewportGo.transform.SetParent(
                scrollGo.transform, false);

            var vpRect =
                viewportGo.GetComponent<RectTransform>();
            vpRect.anchorMin = Vector2.zero;
            vpRect.anchorMax = Vector2.one;
            vpRect.offsetMin = Vector2.zero;
            vpRect.offsetMax = Vector2.zero;

            trackScrollRect.viewport = vpRect;
        }

        if (trackContent == null)
        {
            var contentGo = new GameObject(
                "Content",
                typeof(RectTransform),
                typeof(HorizontalLayoutGroup),
                typeof(ContentSizeFitter));

            Transform parent =
                trackScrollRect.viewport != null
                    ? trackScrollRect.viewport
                    : trackScrollRect.transform;

            contentGo.transform.SetParent(parent, false);

            trackContent =
                contentGo.GetComponent<RectTransform>();
            trackContent.anchorMin =
                new Vector2(0f, 0f);
            trackContent.anchorMax =
                new Vector2(0f, 1f);
            trackContent.pivot =
                new Vector2(0f, 0.5f);
            trackContent.offsetMin = Vector2.zero;
            trackContent.offsetMax = Vector2.zero;

            var hlg = contentGo
                .GetComponent<HorizontalLayoutGroup>();
            hlg.childAlignment = TextAnchor.MiddleLeft;
            hlg.childControlWidth = false;
            hlg.childControlHeight = false;
            hlg.childForceExpandWidth = false;
            hlg.childForceExpandHeight = false;
            hlg.spacing = 0f;
            hlg.padding =
                new RectOffset(20, 20, 10, 10);

            var csf = contentGo
                .GetComponent<ContentSizeFitter>();
            csf.horizontalFit =
                ContentSizeFitter.FitMode.PreferredSize;
            csf.verticalFit =
                ContentSizeFitter.FitMode.Unconstrained;

            trackScrollRect.content = trackContent;
        }
    }

    private void RebuildNodes()
    {
        _lastSelected = null;
        _selectedNodeIndex = -1;

        for (int i = _nodeRefs.Count - 1; i >= 0; i--)
        {
            if (_nodeRefs[i].root != null)
            {
                Destroy(_nodeRefs[i].root.gameObject);
            }
        }

        _nodeRefs.Clear();

        for (int i = _connectors.Count - 1; i >= 0; i--)
        {
            if (_connectors[i].root != null)
            {
                Destroy(_connectors[i].root);
            }
        }

        _connectors.Clear();

        if (config == null)
        {
            return;
        }

        int totalNodes = 0;
        var starters = config.StarterBalls;

        for (int i = 0; i < starters.Count; i++)
        {
            if (starters[i] == null)
            {
                continue;
            }

            if (totalNodes > 0)
            {
                _connectors.Add(BuildConnector());
            }

            var node = BuildNode(
                starters[i].GetSafeDisplayName(),
                starters[i].Icon,
                0d,
                isStarter: true);

            node.ball = starters[i];
            node.isStarter = true;
            _nodeRefs.Add(node);
            AttachTooltipEvents(node);
            totalNodes++;
        }

        var starterComps = config.StarterComponents;

        for (int i = 0; i < starterComps.Count; i++)
        {
            if (starterComps[i] == null)
            {
                continue;
            }

            if (totalNodes > 0)
            {
                _connectors.Add(BuildConnector());
            }

            var node = BuildNode(
                starterComps[i].GetSafeDisplayName(),
                starterComps[i].Icon,
                0d,
                isStarter: true);

            node.component = starterComps[i];
            node.isStarter = true;
            _nodeRefs.Add(node);
            AttachTooltipEvents(node);
            totalNodes++;
        }

        var tiers = config.Tiers;
        double prevThreshold = 0d;

        for (int i = 0; i < tiers.Count; i++)
        {
            if (tiers[i] == null || !tiers[i].HasValidReward)
            {
                continue;
            }

            double threshold = tiers[i].XpThreshold;

            if (totalNodes > 0)
            {
                _connectors.Add(BuildConnector());
            }

            if (tiers[i].HasValidBallReward)
            {
                var ball = tiers[i].RewardBall;

                var node = BuildNode(
                    ball.GetSafeDisplayName(),
                    ball.Icon,
                    threshold,
                    isStarter: false);

                node.ball = ball;
                node.isStarter = false;
                node.nodeThreshold = threshold;
                node.nodePrevThreshold = prevThreshold;
                _nodeRefs.Add(node);
                AttachTooltipEvents(node);
                totalNodes++;
            }
            else if (tiers[i].HasValidComponentReward)
            {
                var comp = tiers[i].RewardComponent;

                var node = BuildNode(
                    comp.GetSafeDisplayName(),
                    comp.Icon,
                    threshold,
                    isStarter: false);

                node.component = comp;
                node.isStarter = false;
                node.nodeThreshold = threshold;
                node.nodePrevThreshold = prevThreshold;
                _nodeRefs.Add(node);
                AttachTooltipEvents(node);
                totalNodes++;
            }

            prevThreshold = threshold;
        }
    }

    private TierNodeRefs BuildNode(
        string displayName,
        Sprite icon,
        double xpThreshold,
        bool isStarter)
    {
        if (tierNodePrefab != null)
        {
            return BuildNodeFromPrefab(
                displayName, icon,
                xpThreshold, isStarter);
        }

        return BuildNodeFromCode(
            displayName, icon,
            xpThreshold, isStarter);
    }

    private TierNodeRefs BuildNodeFromPrefab(
        string displayName,
        Sprite icon,
        double xpThreshold,
        bool isStarter)
    {
        var go = Instantiate(tierNodePrefab, trackContent);
        var refs = new TierNodeRefs
        {
            root = go.GetComponent<RectTransform>()
        };

        var images =
            go.GetComponentsInChildren<Image>(true);

        for (int i = 0; i < images.Length; i++)
        {
            if (images[i].gameObject.name == "Icon")
            {
                refs.iconImage = images[i];
            }
            else if (images[i].gameObject.name
                == "ProgressFill")
            {
                refs.progressFill = images[i];
            }
        }

        var texts =
            go.GetComponentsInChildren<TMP_Text>(true);

        for (int i = 0; i < texts.Length; i++)
        {
            if (texts[i].gameObject.name == "Name")
            {
                refs.nameText = texts[i];
            }
            else if (texts[i].gameObject.name
                == "Threshold")
            {
                refs.thresholdText = texts[i];
            }
        }

        var lockT = go.transform.Find("Lock");

        if (lockT != null)
        {
            refs.lockOverlay = lockT.gameObject;
        }

        var btn = go.GetComponentInChildren<Button>();

        if (btn == null)
        {
            var img = go.GetComponent<Image>();

            if (img == null)
            {
                img = go.AddComponent<Image>();
                img.color = Color.clear;
            }

            btn = go.AddComponent<Button>();
            btn.transition =
                Selectable.Transition.None;
            btn.targetGraphic = img;
        }

        refs.cardButton = btn;

        if (go.GetComponent<ControllerFocusHighlight>()
            == null)
        {
            go.AddComponent<ControllerFocusHighlight>();
        }

        ApplyNodeData(
            refs, displayName, icon,
            xpThreshold, isStarter);

        return refs;
    }

