    }

    private static Sprite GetCircleSprite()
    {
        if (_circleSprite != null)
        {
            return _circleSprite;
        }

        const int size = 64;
        var tex = new Texture2D(
            size, size, TextureFormat.RGBA32, false);

        float center = size / 2f;
        float radius = center - 1f;

        for (int y = 0; y < size; y++)
        {
            for (int x = 0; x < size; x++)
            {
                float dist = Vector2.Distance(
                    new Vector2(x, y),
                    new Vector2(center, center));

                float a =
                    Mathf.Clamp01(radius - dist);

                tex.SetPixel(
                    x, y, new Color(1f, 1f, 1f, a));
            }
        }

        tex.Apply();

        _circleSprite = Sprite.Create(
            tex,
            new Rect(0, 0, size, size),
            new Vector2(0.5f, 0.5f));

        return _circleSprite;
    }

    private static void ApplyNodeData(
        TierNodeRefs refs,
        string displayName,
        Sprite icon,
        double xpThreshold,
        bool isStarter)
    {
        if (refs.iconImage != null && icon != null)
        {
            refs.iconImage.sprite = icon;
        }

        if (refs.nameText != null)
        {
            refs.nameText.text = displayName;
        }

        if (refs.thresholdText != null)
        {
            refs.thresholdText.text = isStarter
                ? "Starter"
                : FormatXp(xpThreshold);
        }
    }

    private void UpdateNodeStates()
    {
        if (config == null)
        {
            return;
        }

        double xp =
            ProgressionService.Instance != null
                ? ProgressionService.Instance
                    .GetCurrentXp()
                : 0d;

        for (int i = 0; i < _nodeRefs.Count; i++)
        {
            var refs = _nodeRefs[i];
            bool unlocked = refs.isStarter
                || xp >= refs.nodeThreshold;

            if (refs.lockOverlay != null)
            {
                refs.lockOverlay.SetActive(!unlocked);
            }

            var bg = refs.cardBg != null
                ? refs.cardBg
                : refs.root.GetComponent<Image>();

            if (bg != null)
            {
                bg.color = unlocked
                    ? unlockedColor
                    : lockedColor;
            }

            if (refs.progressFill != null)
            {
                float fill;

                if (refs.isStarter || unlocked)
                {
                    fill = 1f;
                }
                else
                {
                    double range =
                        refs.nodeThreshold
                        - refs.nodePrevThreshold;

                    fill = range > 0d
                        ? Mathf.Clamp01(
                            (float)(
                                (xp
                                    - refs
                                        .nodePrevThreshold)
                                / range))
                        : 0f;
                }

                refs.progressFill
                    .rectTransform.anchorMax =
                    new Vector2(fill, 1f);
            }

            if (refs.timelineBarFill != null)
            {
                float nodeFill =
                    (refs.isStarter || unlocked)
                        ? 1f
                        : 0f;

                refs.timelineBarFill
                    .rectTransform.anchorMax =
                    new Vector2(nodeFill, 1f);
            }

            if (refs.timelineDot != null)
            {
                refs.timelineDot.color =
                    (refs.isStarter || unlocked)
                        ? progressBarFillColor
                        : progressBarBgColor;
            }
        }

        for (int c = 0; c < _connectors.Count; c++)
        {
            if (_connectors[c].fill == null)
            {
                continue;
            }

            int nextIdx = c + 1;
            float connFill = 0f;

            if (nextIdx < _nodeRefs.Count)
            {
                var next = _nodeRefs[nextIdx];

                if (next.isStarter)
                {
                    connFill = 1f;
                }
                else
                {
                    double threshold =
                        next.nodeThreshold;

                    if (xp >= threshold)
                    {
                        connFill = 1f;
                    }
                    else
                    {
                        double prev =
                            next.nodePrevThreshold;

                        double range =
                            threshold - prev;

                        connFill = range > 0d
                            ? Mathf.Clamp01(
                                (float)(
                                    (xp - prev)
                                    / range))
                            : 0f;
                    }
                }
            }

            _connectors[c].fill
                .rectTransform.anchorMax =
                new Vector2(connFill, 1f);
        }
    }

    private void UpdateHeaderTexts()
    {
        double xp =
            ProgressionService.Instance != null
                ? ProgressionService.Instance
                    .GetCurrentXp()
                : 0d;

        if (xpTotalText != null)
        {
            xpTotalText.text =
                $"Total Score Earned: {FormatXp(xp)}";
        }

        if (nextUnlockText != null)
        {
            ProgressionTier next =
                ProgressionService.Instance != null
                    ? ProgressionService.Instance
                        .GetNextLockedTier()
                    : null;

            if (next != null && next.HasValidReward)
            {
                double remaining =
                    next.XpThreshold - xp;

                string rewardName =
                    GetTierRewardName(next);

                nextUnlockText.text =
                    $"Next: {rewardName}"
                    + $" in {FormatXp(remaining)}";
            }
            else
            {
                nextUnlockText.text =
                    "All rewards unlocked!";
            }
        }
    }

    private static string GetTierRewardName(
        ProgressionTier tier)
    {
        if (tier.HasValidBallReward)
        {
            return tier.RewardBall
                .GetSafeDisplayName();
        }

        if (tier.HasValidComponentReward)
        {
            return tier.RewardComponent
                .GetSafeDisplayName();
        }

        return "Unknown";
    }

    private void SetupGamepadNavigation()
    {
        for (int i = 0; i < _nodeRefs.Count; i++)
        {
            var button = _nodeRefs[i].cardButton;

            if (button == null)
            {
                continue;
            }

            var nav = new Navigation
            {
                mode = Navigation.Mode.Explicit
            };

            if (i > 0)
            {
                nav.selectOnLeft =
                    _nodeRefs[i - 1].cardButton;
            }

            if (i < _nodeRefs.Count - 1)
            {
                nav.selectOnRight =
                    _nodeRefs[i + 1].cardButton;
            }

            button.navigation = nav;
        }
    }

    private void SelectInitialNode()
    {
        if (_nodeRefs.Count == 0
            || EventSystem.current == null)
        {
            return;
        }

        int selectIndex = 0;

        for (int i = 0; i < _nodeRefs.Count; i++)
        {
            if (_nodeRefs[i].lockOverlay != null
                && _nodeRefs[i].lockOverlay.activeSelf)
            {
                selectIndex = Mathf.Max(0, i - 1);
                break;
            }

            selectIndex = i;
        }

        if (_nodeRefs[selectIndex].cardButton != null)
        {
            EventSystem.current
                .SetSelectedGameObject(
                    _nodeRefs[selectIndex]
                        .cardButton.gameObject);
        }

        ScrollToNode(selectIndex);
    }

    private void TrackSelectionForTooltip()
    {
        if (EventSystem.current == null)
        {
            return;
        }

        var selected = EventSystem.current
            .currentSelectedGameObject;

        if (selected == _lastSelected)
        {
            return;
        }

        _lastSelected = selected;

        for (int i = 0; i < _nodeRefs.Count; i++)
        {
            if (_nodeRefs[i].cardButton != null
                && _nodeRefs[i].cardButton.gameObject
                    == selected)
            {
                _selectedNodeIndex = i;
                ShowTooltip(_nodeRefs[i]);
                ScrollToNode(i);
                return;
            }
        }

        if (_selectedNodeIndex >= 0)
        {
            _selectedNodeIndex = -1;
            HideTooltip();
        }
    }

    private void ScrollToNode(int index)
    {
        if (trackScrollRect == null
            || _nodeRefs.Count == 0)
        {
            return;
        }

        if (index < 0 || index >= _nodeRefs.Count)
        {
            return;
        }

        Canvas.ForceUpdateCanvases();

        RectTransform viewportRect =
            trackScrollRect.viewport != null
                ? trackScrollRect.viewport
                : trackScrollRect
                    .GetComponent<RectTransform>();

        float contentWidth =
            trackContent.rect.width;

        float viewportWidth =
            viewportRect.rect.width;

        if (contentWidth <= viewportWidth)
        {
            return;
        }

        float nodeX =
            _nodeRefs[index].root.localPosition.x
            + _nodeRefs[index].root.rect.width * 0.5f;

        float targetX =
            nodeX - viewportWidth * 0.5f;

        float maxScroll =
            contentWidth - viewportWidth;

        trackScrollRect
            .horizontalNormalizedPosition =
            Mathf.Clamp01(targetX / maxScroll);
    }

    private void AttachTooltipEvents(TierNodeRefs node)
    {
        var trigger = node.root.gameObject
            .AddComponent<EventTrigger>();

        var enterEntry = new EventTrigger.Entry
        {
            eventID = EventTriggerType.PointerEnter
        };

        enterEntry.callback.AddListener(_ =>
            ShowTooltip(node));

        var exitEntry = new EventTrigger.Entry
        {
            eventID = EventTriggerType.PointerExit
        };

        exitEntry.callback.AddListener(_ =>
            HideTooltip());

        trigger.triggers.Add(enterEntry);
        trigger.triggers.Add(exitEntry);
    }

    private void ShowTooltip(TierNodeRefs node)
    {
        string title = null;
        string desc = null;

        if (node.ball != null)
        {
            title = node.ball.GetSafeDisplayName();
            desc = node.ball.Description;
        }
        else if (node.component != null)
        {
            title =
                node.component.GetSafeDisplayName();
            desc = node.component.Description;
        }

        if (title == null)
        {
            return;
        }

        TooltipManager.Show(title, desc);
    }

    private void HideTooltip()
    {
        TooltipManager.Hide();
    }

    private static string FormatXp(double value)
    {
        if (value >= 1_000_000d)
        {
            return $"{value / 1_000_000d:F1}M";
        }

        if (value >= 1_000d)
        {
            return $"{value / 1_000d:F1}K";
        }

        return $"{value:N0}";
    }
}
